import{_ as e,o as s,c as o,g as t}from"./chunks/framework.CpTXwe1b.js";const v=JSON.parse('{"title":"反果为因","description":"","frontmatter":{"title":"反果为因","date":"2015-05-14T13:48:16.496Z","length":"344字","time":"2分钟","aside":false,"hash":1582071543},"headers":[],"relativePath":"article/反果为因.md","filePath":"article/反果为因.md"}'),n={name:"article/反果为因.md"},_=t("p",null,"常常遇上这样的类似事例。",-1),l=t("p",null,"一则股票将暴涨的消息传遍人群，人们纷纷大量注资股市，股票果然暴涨。但暴涨的原因却非消息的预测，而是人们的大量注资。",-1),a=t("p",null,"另一则实例则是有名的心理学实验。专家给老师一份“潜力”学生的名单，告诉老师这些学生很有“潜力”。一学期后，名单上学生果然表现了极大的进步。但其进步的原因却非专家的预测，而是老师对他们下意识的关注与培养。",-1),c=t("p",null,"同样的情况还有很多，它们的共性是：",-1),i=t("p",null,"对于事件 A 将发生的预测，人群选择了相信，在相信后所作所为直接导致了 A 的发生。",-1),d=t("p",null,"其实用反果为因的短语描述这一情形仍较不妥，这是一种“信则有，不信则无”的事件。因为是否相信，决定了事件原因，决定了事件走向。（其实是相信后的所为）",-1),r=t("p",null,"这是又一个观察者与观察对象发生纠缠的例子。观察者同时包含了纯观察行为并保留了对观察对象施加作用之能力。",-1),p=t("p",null,"还有一个是伏地魔的例子，它选择相信那个预言，并亲手塑造了掘墓人。",-1),h=[_,l,a,c,i,d,r,p];function u(m,f,$,g,x,B){return s(),o("div",null,h)}const A=e(n,[["render",u]]);export{v as __pageData,A as default};
